#include <iostream>

class Point {
public:
    int x;
    int y;

    Point(int x_coord = 0, int y_coord = 0) : x(x_coord), y(y_coord) {}

    const Point& operator++() {
        ++x;
        ++y;
        return *this;
    }

    void print() const {
        std::cout << "(" << x << ", " << y << ")";
    }
};

int main() {
    Point p1(1, 2);
    std::cout << "Original point p1: ";
    p1.print();
    std::cout << std::endl;

    ++p1;
    std::cout << "After ++p1: ";
    p1.print();
    std::cout << std::endl;

    Point p2(5, 6);
    std::cout << "Original point p2: ";
    p2.print();
    std::cout << std::endl;

    const Point& temp_ref = ++p2;
    std::cout << "After ++p2 (temp_ref points to p2): ";
    temp_ref.print();
    std::cout << std::endl;

    std::cout << "Final p2: ";
    p2.print();
    std::cout << std::endl;

    return 0;
}
